// ─── Debounce hook ────────────────────────────────────────────────────────────
function useDebounce(value, delay=150) {
  const [debounced, setDebounced] = React.useState(value);
  React.useEffect(() => {
    const t = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(t);
  }, [value, delay]);
  return debounced;
}

// ─── Skeleton loader component ────────────────────────────────────────────────
function Skeleton({ w="100%", h=14, r=6, style }) {
  return <div className="wz-skeleton" style={{ width:w, height:h, borderRadius:r, ...style }}/>;
}

// ─── Utility: lighten a hex colour for dark mode text ─────────────────────────
function lightenHex(hex, pct) {
  try {
    const n = parseInt(hex.replace("#",""), 16);
    const r = Math.min(255, (n>>16) + Math.round(pct*2.55));
    const g = Math.min(255, ((n>>8)&0xFF) + Math.round(pct*2.55));
    const b = Math.min(255, (n&0xFF) + Math.round(pct*2.55));
    return `#${((1<<24)+(r<<16)+(g<<8)+b).toString(16).slice(1)}`;
  } catch { return hex; }
}

// ─── Hooks ────────────────────────────────────────────────────────────────────
function useLocal(key, def) {
  const [v, setV] = React.useState(() => {
    try { const s = localStorage.getItem(key); return s !== null ? JSON.parse(s) : def; }
    catch { return def; }
  });
  const set = React.useCallback(fn => setV(prev => {
    const next = typeof fn === 'function' ? fn(prev) : fn;
    try { localStorage.setItem(key, JSON.stringify(next)); } catch {}
    return next;
  }), [key]);
  return [v, set];
}
function useSession(key, def) {
  const [v, setV] = React.useState(() => {
    try { const s = sessionStorage.getItem(key); return s !== null ? JSON.parse(s) : def; }
    catch { return def; }
  });
  const set = React.useCallback(fn => setV(prev => {
    const next = typeof fn === 'function' ? fn(prev) : fn;
    try { sessionStorage.setItem(key, JSON.stringify(next)); } catch {}
    return next;
  }), [key]);
  const clear = React.useCallback(() => {
    try { sessionStorage.removeItem(key); } catch {}
    setV(def);
  }, [key]);
  return [v, set, clear];
}

// ─── Theme Context ────────────────────────────────────────────────────────────
const ThemeCtx = React.createContext(LIGHT);
const useT = () => React.useContext(ThemeCtx);

// ─── Live schema context (fetched once from /api/tables) ─────────────────────
const SchemaCtx = React.createContext("");
const useSchema = () => React.useContext(SchemaCtx);

// Compact schema string: "schema.table(col1,col2,...); ..."  — max 120 cols total
function buildSchemaStr(tables) {
  if (!tables || tables.length === 0) return "";
  // Group by schema.table
  const grouped = {};
  for (const row of tables) {
    const key = `${row.table_schema}.${row.table_name}`;
    if (!grouped[key]) grouped[key] = [];
    if (row.column_name) grouped[key].push(row.column_name);
  }
  return Object.entries(grouped)
    .map(([tbl, cols]) => cols.length ? `${tbl}(${cols.join(",")})` : tbl)
    .join("; ");
}

// ─── Shared UI atoms ──────────────────────────────────────────────────────────
function Badge({ label, color, pulse }) {
  const T = useT();
  const c = color || T.accent;
  // Solid fills for known severity labels, transparent for others
  const isSev = ["critical","high","medium","low","info"].includes(label?.toLowerCase());
  const SEV_SOLID = {
    critical: { bg:"#FEE2E2", text:"#991B1B", border:"#FECACA" },
    high:     { bg:"#FEF3C7", text:"#92400E", border:"#FDE68A" },
    medium:   { bg:"#FFF7ED", text:"#9A3412", border:"#FED7AA" },
    low:      { bg:"#ECFDF5", text:"#065F46", border:"#A7F3D0" },
    info:     { bg:"#EFF6FF", text:"#1E40AF", border:"#BFDBFE" },
  };
  const dark_SEV_SOLID = {
    critical: { bg:"rgba(239,68,68,0.18)",  text:"#FCA5A5", border:"rgba(239,68,68,0.3)" },
    high:     { bg:"rgba(251,146,60,0.18)", text:"#FED7AA", border:"rgba(251,146,60,0.3)" },
    medium:   { bg:"rgba(234,179,8,0.16)",  text:"#FDE68A", border:"rgba(234,179,8,0.28)" },
    low:      { bg:"rgba(52,211,153,0.16)", text:"#6EE7B7", border:"rgba(52,211,153,0.28)" },
    info:     { bg:"rgba(99,102,241,0.16)", text:"#A5B4FC", border:"rgba(99,102,241,0.28)" },
  };
  const sev = label?.toLowerCase();
  const solidStyle = isSev
    ? (T.isDark ? dark_SEV_SOLID[sev] : SEV_SOLID[sev]) || null
    : null;
  return (
    <span style={{
      display:"inline-flex", alignItems:"center", gap:4,
      padding:"2px 8px 2px 7px", borderRadius:99, fontSize:9, fontWeight:700,
      letterSpacing:"0.05em", textTransform:"uppercase",
      background: solidStyle ? solidStyle.bg : T.isDark ? `${c}22` : `${c}14`,
      color: solidStyle ? solidStyle.text : T.isDark ? lightenHex(c, 30) : c,
      border:`1px solid ${solidStyle ? solidStyle.border : c+(T.isDark?"40":"28")}`,
    }}>
      <span style={{
        width:5, height:5, borderRadius:"50%", flexShrink:0,
        background: solidStyle ? solidStyle.text : c,
        animation: pulse ? "pulse 1.5s infinite" : "none",
        boxShadow: pulse ? `0 0 6px ${c}80` : "none",
      }}/>
      {label}
    </span>
  );
}

function Card({ children, style, onClick, hoverable }) {
  const T = useT();
  const glassStyle = T.isDark ? {
    background: "rgba(255,255,255,0.04)",
    backdropFilter: "blur(16px)",
    WebkitBackdropFilter: "blur(16px)",
    border: `1px solid rgba(255,255,255,0.08)`,
    boxShadow: "0 1px 3px rgba(0,0,0,0.3), inset 0 1px 0 rgba(255,255,255,0.05)",
  } : {
    background: T.card,
    border: `1px solid ${T.border2||"#E4E7EC"}`,
    boxShadow: "0 1px 3px rgba(0,0,0,0.06), 0 1px 2px rgba(0,0,0,0.04)",
  };
  return (
    <div
      onClick={onClick}
      className={hoverable||onClick ? "wz-card-hover" : undefined}
      style={{
        ...glassStyle,
        borderRadius:10,
        cursor: onClick ? "pointer" : "default",
        ...style
      }}
    >{children}</div>
  );
}

function Btn({ children, onClick, variant="primary", size="md", disabled, style }) {
  const T = useT();
  const base = {
    display:"inline-flex", alignItems:"center", gap:6,
    border:"none", borderRadius:7, fontWeight:600,
    cursor: disabled ? "not-allowed" : "pointer",
    opacity: disabled ? 0.5 : 1,
    transition:"background 0.12s, opacity 0.12s",
    fontSize: size==="sm" ? 11 : size==="lg" ? 14 : 12,
    padding: size==="sm" ? "4px 10px" : size==="lg" ? "10px 22px" : "6px 14px",
  };
  const variantStyle = {
    primary: { background:T.accent, color:"white",
      "--btn-hov": T.accentL },
    ghost:   { background:"transparent", color:T.accent, border:`1px solid ${T.accent}30`,
      "--btn-hov": `${T.accent}18` },
    danger:  { background:"#DC2626", color:"white",
      "--btn-hov": "#EF4444" },
    success: { background:T.green, color:"white",
      "--btn-hov": T.greenL||T.green },
    muted:   { background:T.border, color:T.muted,
      "--btn-hov": T.border2||T.border },
  }[variant] || {};
  return (
    <button
      className={`wizi-btn wizi-btn-${variant}`}
      onClick={!disabled?onClick:undefined}
      style={{...base,...variantStyle,...style}}>
      {children}
    </button>
  );
}

function StatusDot({ status }) {
  const T = useT();
  const colors = {
    healthy:"#10B981", clean:"#10B981", fixed:"#10B981", pass:"#10B981",
    warning:"#F59E0B", pending:"#F59E0B", awaiting_approval:"#F59E0B",
    critical:"#EF4444", error:"#EF4444", failed:"#EF4444", fail:"#EF4444",
    running:"#3B82F6", scanning:"#3B82F6",
    idle:T.dim,
  };
  const c = colors[status] || T.dim;
  const anim =
    status==="running"||status==="scanning" ? "pulseBlue 1.5s ease-in-out infinite" :
    status==="critical"||status==="error"||status==="failed"||status==="fail" ? "pulseRed 2s ease-in-out infinite" :
    status==="warning"||status==="pending"||status==="awaiting_approval" ? "pulseAmber 2.5s ease-in-out infinite" :
    "none";
  return (
    <span style={{
      display:"inline-block", width:8, height:8, borderRadius:"50%",
      background:c, flexShrink:0, animation:anim
    }}/>
  );
}

function Spinner({ size=14, color }) {
  const T = useT();
  return (
    <div style={{
      width:size, height:size, borderRadius:"50%", flexShrink:0,
      border:`${Math.max(1.5, size/8)}px solid ${color ? color+"30" : T.isDark?"rgba(255,255,255,0.1)":T.border2}`,
      borderTopColor: color||T.accent,
      animation:"spin 0.65s cubic-bezier(0.4,0,0.6,1) infinite",
    }}/>
  );
}

function EmptyState({ icon: Icon, title, desc, action }) {
  const T = useT();
  return (
    <div style={{ textAlign:"center", padding:"48px 24px" }}>
      <div style={{ width:48, height:48, borderRadius:12, background:T.border,
        display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 16px" }}>
        <Icon size={22} color={T.muted}/>
      </div>
      <div style={{ fontSize:14, fontWeight:700, color:T.text, marginBottom:6 }}>{title}</div>
      <div style={{ fontSize:12, color:T.muted, marginBottom:action?16:0 }}>{desc}</div>
      {action}
    </div>
  );
}


// ─── Global CSS ───────────────────────────────────────────────────────────────
const GLOBAL_CSS = `
  /* fonts loaded dynamically per theme via <link> */
  *, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }
  body { -webkit-font-smoothing:antialiased; text-rendering:optimizeLegibility; }
  /* scrollbar */
  @keyframes spin { to { transform:rotate(360deg); } }
  @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.4} }
  @keyframes fadeIn { from{opacity:0;transform:translateY(6px)} to{opacity:1;transform:translateY(0)} }
  @keyframes slideIn { from{opacity:0;transform:translateX(-8px)} to{opacity:1;transform:translateX(0)} }
  ::-webkit-scrollbar { width:5px; height:5px; }
  ::-webkit-scrollbar-track { background:transparent; }
  ::-webkit-scrollbar-thumb { background:rgba(128,128,128,0.25); border-radius:99px; }
  .fade-in { animation:fadeIn 0.25s ease; }
  .mono { font-family:'IBM Plex Mono', monospace; }
  .wz-card-hover { transition: border-color 0.12s, box-shadow 0.12s; }
  .wz-card-hover:hover { border-color: rgba(128,128,128,0.35) !important; box-shadow: 0 4px 16px rgba(0,0,0,0.06); }
  /* GPU-accelerated scroll containers */
  .wz-scroll { overflow-y: auto; -webkit-overflow-scrolling: touch; }
  /* Contain layout/paint for tab panels */
  .wz-tab-panel { contain: layout style; }

  /* Btn CSS-only hover — no useState re-renders */
  .wizi-btn { -webkit-font-smoothing: antialiased; }
  .wizi-btn:not([disabled]):hover { opacity: 0.85; }
  .wizi-btn-ghost:not([disabled]):hover { background: var(--btn-hov) !important; opacity: 1; }
  .wizi-btn-muted:not([disabled]):hover { background: var(--btn-hov) !important; opacity: 1; }
  .wizi-btn:active:not([disabled]) { transform: scale(0.97); }
  /* Smooth scrolling globally */
  * { scroll-behavior: smooth; }
  /* Scroll performance */
  main { scroll-behavior: smooth; }
  [style*="overflow-y: auto"], [style*="overflowY"] {
    -webkit-overflow-scrolling: touch;
  }
  /* Tab content — ensure padding at bottom so last card isn't clipped */
  main > .fade-in > div:last-child { padding-bottom: 24px; }
  /* Prevent layout thrash on frequently-updated elements */
  .wizi-run-row { contain: layout style; }
  /* Smooth tab transitions */
  main > * { animation: wizi-fadein 0.15s ease; }
  @keyframes wizi-fadein { from { opacity: 0; transform: translateY(4px); } to { opacity: 1; transform: none; } }
  /* GPU-accelerate scroll containers */
  [data-scroll] { will-change: transform; transform: translateZ(0); }
  /* Remove tap highlight on mobile */
  button, [role="button"] { -webkit-tap-highlight-color: transparent; touch-action: manipulation; }

  /* ── Animation library ── */
  @keyframes countUp { from { opacity:0; transform:translateY(8px) scale(0.92); } to { opacity:1; transform:translateY(0) scale(1); } }
  @keyframes staggerIn { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:translateY(0); } }
  @keyframes modalPop { from { opacity:0; transform:scale(0.94) translateY(8px); } to { opacity:1; transform:scale(1) translateY(0); } }
  @keyframes barFill { from { width:0 !important; } to { } }
  @keyframes pulseRed { 0%,100%{box-shadow:0 0 0 0 rgba(239,68,68,0.4)} 50%{box-shadow:0 0 0 5px rgba(239,68,68,0)} }
  @keyframes pulseAmber { 0%,100%{box-shadow:0 0 0 0 rgba(245,158,11,0.4)} 50%{box-shadow:0 0 0 5px rgba(245,158,11,0)} }
  @keyframes pulseBlue { 0%,100%{box-shadow:0 0 0 0 rgba(59,130,246,0.4)} 50%{box-shadow:0 0 0 5px rgba(59,130,246,0)} }
  .wz-stagger > * { animation: staggerIn 0.25s ease both; }
  .wz-stagger > *:nth-child(1) { animation-delay:0ms; }
  .wz-stagger > *:nth-child(2) { animation-delay:40ms; }
  .wz-stagger > *:nth-child(3) { animation-delay:80ms; }
  .wz-stagger > *:nth-child(4) { animation-delay:120ms; }
  .wz-stagger > *:nth-child(5) { animation-delay:160ms; }
  .wz-stagger > *:nth-child(6) { animation-delay:200ms; }
  .wz-stagger > *:nth-child(n+7) { animation-delay:240ms; }
  .wz-modal-inner { animation: modalPop 0.22s cubic-bezier(0.34,1.56,0.64,1) both; }
  .wz-bar-fill { animation: barFill 0.8s cubic-bezier(0.4,0,0.2,1) both; }
  .wz-kpi-val { animation: countUp 0.35s cubic-bezier(0.34,1.56,0.64,1) both; }

  /* ── Toast enhancements ── */
  @keyframes toastIn { from{opacity:0;transform:translateX(24px) scale(0.95)} to{opacity:1;transform:translateX(0) scale(1)} }
  @keyframes toastOut { from{opacity:1;transform:translateX(0) scale(1)} to{opacity:0;transform:translateX(24px) scale(0.95)} }
  @keyframes toastProgress { from{width:100%} to{width:0%} }
  .wz-toast { animation: toastIn 0.22s cubic-bezier(0.34,1.56,0.64,1) both; }
  .wz-toast-progress { animation: toastProgress linear both; border-radius:0 0 10px 10px; }

  /* ── Sticky table headers ── */
  .wz-table thead th, .wz-table thead td { position:sticky; top:0; z-index:2; }
  .wz-table { border-collapse:separate; border-spacing:0; }
  [style*="overflow-y"] thead tr th, [style*="overflowY"] thead tr th { position:sticky; top:0; z-index:2; }

  /* ── Tab transition ── */
  .wz-tab-enter { animation: tabEnter 0.18s cubic-bezier(0.25,0.46,0.45,0.94) both; }
  @keyframes tabEnter { from{opacity:0;transform:translateY(6px)} to{opacity:1;transform:translateY(0)} }

  /* ── Shortcuts overlay ── */
  .wz-shortcuts-overlay { animation: modalPop 0.2s cubic-bezier(0.34,1.56,0.64,1) both; }
  .wz-kbd { display:inline-flex;align-items:center;justify-content:center;min-width:22px;height:20px;padding:0 5px;border-radius:4px;font-size:10px;font-weight:700;font-family:monospace;border:1px solid rgba(255,255,255,0.15);background:rgba(255,255,255,0.08);color:rgba(255,255,255,0.8); }
`;


// ─── Keyboard Shortcuts Overlay ──────────────────────────────────────────────
function ShortcutsOverlay({ onClose }) {
  const T = useT();
  React.useEffect(() => {
    const h = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", h);
    return () => window.removeEventListener("keydown", h);
  }, [onClose]);
  const SECTIONS = [
    { title:"Navigation", items:[
      { keys:["H"], label:"System Health" },
      { keys:["A"], label:"Auto-Pilot" },
      { keys:["3"], label:"Triage & Monitor" },
      { keys:["4"], label:"Workflows" },
      { keys:["5"], label:"Pipeline Runs" },
      { keys:["R"], label:"Reporting" },
      { keys:["8"], label:"Data Explorer" },
      { keys:["7"], label:"Configure" },
    ]},
    { title:"Global Actions", items:[
      { keys:["⌘","K"], label:"Command Palette" },
      { keys:["?"],      label:"Show this overlay" },
      { keys:["Esc"],    label:"Close modal / overlay" },
    ]},
  ];
  return (
    <div onClick={onClose} style={{ position:"fixed", inset:0, zIndex:10000,
      background:"rgba(0,0,0,0.6)", display:"flex", alignItems:"center", justifyContent:"center",
      backdropFilter:"blur(4px)" }}>
      <div onClick={e=>e.stopPropagation()} className="wz-shortcuts-overlay"
        style={{ background:T.isDark?"#1A1D24":"#1C1E26", borderRadius:16, padding:"24px 28px",
          width:480, maxWidth:"90vw", boxShadow:"0 24px 64px rgba(0,0,0,0.5)",
          border:"1px solid rgba(255,255,255,0.1)" }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:20 }}>
          <div style={{ fontSize:15, fontWeight:800, color:"#fff", letterSpacing:"-0.02em" }}>
            ⌨️ Keyboard Shortcuts
          </div>
          <button onClick={onClose} style={{ background:"rgba(255,255,255,0.08)", border:"none",
            borderRadius:6, width:24, height:24, cursor:"pointer", color:"rgba(255,255,255,0.5)",
            fontSize:14, display:"flex", alignItems:"center", justifyContent:"center" }}>×</button>
        </div>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:20 }}>
          {SECTIONS.map(sec=>(
            <div key={sec.title}>
              <div style={{ fontSize:10, fontWeight:700, color:"rgba(255,255,255,0.35)",
                textTransform:"uppercase", letterSpacing:"0.1em", marginBottom:10 }}>{sec.title}</div>
              <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                {sec.items.map(item=>(
                  <div key={item.label} style={{ display:"flex", alignItems:"center",
                    justifyContent:"space-between", gap:8 }}>
                    <div style={{ fontSize:12, color:"rgba(255,255,255,0.65)" }}>{item.label}</div>
                    <div style={{ display:"flex", gap:3, flexShrink:0 }}>
                      {item.keys.map((k,i)=>(
                        <span key={i} className="wz-kbd">{k}</span>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
        <div style={{ marginTop:20, paddingTop:16, borderTop:"1px solid rgba(255,255,255,0.07)",
          fontSize:10, color:"rgba(255,255,255,0.25)", textAlign:"center" }}>
          Press <span className="wz-kbd">?</span> anytime to show this · <span className="wz-kbd">Esc</span> to close
        </div>
      </div>
    </div>
  );
}

