// ─── Notification / Toast System ─────────────────────────────────────────────
const NotifCtx = React.createContext({ add:()=>{}, items:[] });
const useNotif = () => React.useContext(NotifCtx);

function NotifProvider({ children }) {
  const T = useT();
  const [items, setItems] = React.useState([]);
  const [drawer, setDrawer] = React.useState(false);

  const add = React.useCallback((msg, type="info", opts={}) => {
    const id = Date.now().toString(36) + Math.random().toString(36).slice(2,5);
    const item = { id, msg, type, ts: new Date().toISOString(),
                   read: false, persistent: opts.persistent||false,
                   action: opts.action||null, actionLabel: opts.actionLabel||null };
    setItems(p => [item, ...p].slice(0, 50));
    // Auto-dismiss non-persistent toasts
    if (!opts.persistent) {
      setTimeout(() => setItems(p => p.filter(i => i.id !== id)), opts.duration||4500);
    }
    return id;
  }, []);

  const dismiss   = React.useCallback((id) => setItems(p => p.filter(i => i.id !== id)), []);
  const markRead  = React.useCallback((id) => setItems(p => p.map(i => i.id===id?{...i,read:true}:i)), []);
  const markAllRead = React.useCallback(() => setItems(p => p.map(i => ({...i,read:true}))), []);
  const clearAll  = React.useCallback(() => setItems([]), []);
  const acknowledge = React.useCallback((id, by="me") => setItems(p => p.map(i =>
    i.id===id?{...i,read:true,acked:true,ackedBy:by,ackedAt:new Date().toISOString()}:i
  )), []);
  const snooze = React.useCallback((id, mins=30) => {
    const until = new Date(Date.now()+mins*60*1000).toISOString();
    setItems(p => p.map(i => i.id===id?{...i,snoozed:true,snoozeUntil:until}:i));
    setTimeout(()=>setItems(p=>p.map(i=>i.id===id?{...i,snoozed:false,snoozeUntil:null}:i)), mins*60*1000);
  }, []);
  const unread = items.filter(i => !i.read && !i.snoozed).length;

  const TYPE_STYLE = {
    success: { bg:"#10B981", icon:"✓", label:"Success" },
    error:   { bg:"#EF4444", icon:"✗", label:"Error"   },
    warning: { bg:"#F59E0B", icon:"⚠", label:"Warning" },
    info:    { bg:"#6366F1", icon:"ℹ", label:"Info"    },
    run:     { bg:"#8B5CF6", icon:"▶", label:"Run"     },
  };

  return (
    <NotifCtx.Provider value={{ add, items, unread, drawer, setDrawer, markRead, markAllRead, clearAll, dismiss, acknowledge, snooze }}>
      {children}

      {/* Toast stack — bottom-right */}
      <div style={{ position:"fixed", bottom:24, right:24, zIndex:9999,
        display:"flex", flexDirection:"column", gap:8, pointerEvents:"none",
        maxWidth:360 }}>
        {items.filter(i=>!i.read&&!i.persistent).slice(0,4).map((item,idx) => {
          const s = TYPE_STYLE[item.type] || TYPE_STYLE.info;
          const duration = 4500;
          return (
            <div key={item.id}
              className="wz-toast"
              style={{ display:"flex", flexDirection:"column", pointerEvents:"all",
                borderRadius:10, overflow:"hidden",
                background: T.isDark ? T.card : "#1A1C23",
                boxShadow:`0 8px 32px rgba(0,0,0,0.4), 0 0 0 1px rgba(255,255,255,0.07)`,
                border:`1px solid ${s.bg}30`,
                maxWidth:360, animationDelay:`${idx*30}ms` }}>
              {/* Main content row */}
              <div style={{ display:"flex", alignItems:"flex-start", gap:10, padding:"12px 14px" }}>
                <div style={{ width:24, height:24, borderRadius:7, flexShrink:0,
                  background:`${s.bg}20`, border:`1px solid ${s.bg}40`,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:12, fontWeight:800, color:s.bg, marginTop:1 }}>{s.icon}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:10, fontWeight:700, color:s.bg,
                    textTransform:"uppercase", letterSpacing:"0.06em", marginBottom:2 }}>{s.label}</div>
                  <div style={{ fontSize:12, fontWeight:500, color:"rgba(255,255,255,0.88)",
                    lineHeight:1.45, wordBreak:"break-word" }}>{item.msg}</div>
                  {item.action && (
                    <button onClick={item.action}
                      style={{ marginTop:5, fontSize:11, color:s.bg, background:"none",
                        border:"none", cursor:"pointer", padding:0, fontWeight:600 }}>
                      {item.actionLabel||"View →"}
                    </button>
                  )}
                </div>
                <button onClick={()=>dismiss(item.id)}
                  style={{ background:"none", border:"none", cursor:"pointer",
                    color:"rgba(255,255,255,0.3)", fontSize:16, lineHeight:1,
                    padding:0, flexShrink:0, marginTop:1 }}>×</button>
              </div>
              {/* Progress bar */}
              <div style={{ height:3, background:`rgba(255,255,255,0.06)` }}>
                <div className="wz-toast-progress"
                  style={{ height:"100%", background:s.bg, animationDuration:`${duration}ms` }}/>
              </div>
            </div>
          );
        })}
      </div>

      {/* Notification Drawer */}
      {drawer && (
        <div style={{ position:"fixed", inset:0, zIndex:8000 }}
          onClick={()=>setDrawer(false)}>
          <div style={{ position:"absolute", top:0, right:0, width:380, height:"100%",
            background:T.card, boxShadow:"-8px 0 32px rgba(0,0,0,0.2)",
            display:"flex", flexDirection:"column",
            borderLeft:`1px solid ${T.border2}` }}
            onClick={e=>e.stopPropagation()}>

            {/* Header */}
            <div style={{ padding:"16px 20px", borderBottom:`1px solid ${T.border}`,
              display:"flex", alignItems:"center", gap:10 }}>
              <Bell size={15} color={T.muted}/>
              <span style={{ fontSize:14, fontWeight:700, color:T.text, flex:1 }}>
                Notifications
              </span>
              {unread > 0 && (
                <button onClick={markAllRead}
                  style={{ fontSize:11, color:"#6366F1", background:"none",
                    border:"none", cursor:"pointer", fontWeight:600 }}>
                  Mark all read
                </button>
              )}
              {items.length > 0 && (
                <button onClick={clearAll}
                  style={{ fontSize:11, color:"#9CA3AF", background:"none",
                    border:"none", cursor:"pointer" }}>
                  Clear
                </button>
              )}
              <button onClick={()=>setDrawer(false)}
                style={{ background:"none", border:"none", cursor:"pointer",
                  color:T.muted, fontSize:18, lineHeight:1 }}>×</button>
            </div>

            {/* Items */}
            <div style={{ flex:1, overflowY:"auto" }}>
              {items.length === 0 ? (
                <div style={{ textAlign:"center", padding:"60px 24px", color:T.muted }}>
                  <Bell size={32} color={T.dim} style={{ opacity:0.4, marginBottom:12, display:"block", margin:"0 auto 12px" }}/>
                  <div style={{ fontSize:13, fontWeight:600, color:T.text2 }}>All caught up</div>
                  <div style={{ fontSize:11, marginTop:4, color:T.muted }}>No notifications yet</div>
                </div>
              ) : items.filter(i=>!i.snoozed).map(item => {
                const s = TYPE_STYLE[item.type] || TYPE_STYLE.info;
                return (
                  <div key={item.id} onClick={()=>markRead(item.id)}
                    style={{ padding:"12px 20px", borderBottom:`1px solid ${T.border}`,
                      display:"flex", gap:10, cursor:"pointer",
                      background: item.acked ? `${T.green}04` : item.read ? "transparent" : `${T.accent}06`,
                      transition:"background 0.1s" }}
                    onMouseEnter={e=>e.currentTarget.style.background=`${T.accent}08`}
                    onMouseLeave={e=>e.currentTarget.style.background=item.acked?`${T.green}04`:item.read?"transparent":`${T.accent}06`}>
                    <div style={{ width:22, height:22, borderRadius:6, flexShrink:0,
                      background:item.acked?T.green:s.bg, display:"flex", alignItems:"center",
                      justifyContent:"center", fontSize:11, fontWeight:700,
                      color:"white", marginTop:2 }}>{item.acked?"✓":s.icon}</div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:12, color:T.text, lineHeight:1.4 }}>{item.msg}</div>
                      <div style={{ fontSize:10, color:T.dim, marginTop:3, display:"flex", gap:8 }}>
                        <span>{new Date(item.ts).toLocaleTimeString()}</span>
                        {item.acked&&<span style={{color:T.green,fontWeight:600}}>✓ Acknowledged {item.ackedAt?new Date(item.ackedAt).toLocaleTimeString():""}</span>}
                      </div>
                      {item.action && (
                        <button onClick={(e)=>{e.stopPropagation();item.action();}}
                          style={{ marginTop:4, fontSize:11, color:s.bg, background:"none",
                            border:"none", cursor:"pointer", padding:0, fontWeight:600 }}>
                          {item.actionLabel||"View →"}
                        </button>
                      )}
                      {/* Ack + Snooze buttons */}
                      {!item.acked&&(
                        <div style={{display:"flex",gap:5,marginTop:5}}>
                          <button onClick={(e)=>{e.stopPropagation();acknowledge(item.id);}}
                            style={{fontSize:9,padding:"2px 8px",borderRadius:5,cursor:"pointer",
                              border:`1px solid ${T.green}30`,background:`${T.green}08`,
                              color:T.green,fontWeight:600}}>
                            ✓ Ack
                          </button>
                          <button onClick={(e)=>{e.stopPropagation();snooze(item.id,30);}}
                            style={{fontSize:9,padding:"2px 8px",borderRadius:5,cursor:"pointer",
                              border:`1px solid ${T.border}`,background:"none",
                              color:T.muted}}>
                            ⏱ 30m
                          </button>
                          <button onClick={(e)=>{e.stopPropagation();snooze(item.id,120);}}
                            style={{fontSize:9,padding:"2px 8px",borderRadius:5,cursor:"pointer",
                              border:`1px solid ${T.border}`,background:"none",
                              color:T.muted}}>
                            ⏱ 2h
                          </button>
                        </div>
                      )}
                    </div>
                    {!item.read && !item.acked && (
                      <div style={{ width:7, height:7, borderRadius:"50%",
                        background:"#6366F1", flexShrink:0, marginTop:6 }}/>
                    )}
                    <button onClick={(e)=>{e.stopPropagation();dismiss(item.id);}}
                      style={{ background:"none", border:"none", cursor:"pointer",
                        color:T.muted, fontSize:14, lineHeight:1, flexShrink:0 }}>×</button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </NotifCtx.Provider>
  );
}

// Bell button — used in Sidebar
function BellButton({ collapsed }) {
  const T = useT();
  const { unread, setDrawer } = useNotif();
  return (
    <button onClick={()=>setDrawer(d=>!d)}
      title="Notifications"
      style={{ width:"100%", display:"flex", alignItems:"center",
        gap: collapsed ? 0 : 10,
        padding: collapsed ? "8px 0" : "8px 10px",
        justifyContent: collapsed ? "center" : "flex-start",
        borderRadius:7, border:"none",
        background: unread > 0 ? `${T.navActiveBg||T.accent+"18"}` : "transparent",
        color: unread > 0 ? (T.navActiveText||T.accent) : "rgba(255,255,255,0.4)",
        cursor:"pointer", transition:"all 0.15s", fontFamily:"inherit",
        position:"relative" }}
      onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,0.05)";e.currentTarget.style.color="rgba(255,255,255,0.7)";}}
      onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color="rgba(255,255,255,0.4)";}}>
      <div style={{ position:"relative", flexShrink:0 }}>
        <Bell size={14} strokeWidth={1.8}/>
        {unread > 0 && (
          <div style={{ position:"absolute", top:-4, right:-4,
            width:14, height:14, borderRadius:99, background:"#EF4444",
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:8, fontWeight:700, color:"white" }}>
            {unread > 9 ? "9+" : unread}
          </div>
        )}
      </div>
      {!collapsed && (
        <span style={{ fontSize:12, fontWeight:400, flex:1 }}>Notifications</span>
      )}
      {!collapsed && unread > 0 && (
        <span style={{ minWidth:18, height:18, borderRadius:99, padding:"0 5px",
          background:"#EF4444", color:"white", fontSize:9, fontWeight:700,
          display:"flex", alignItems:"center", justifyContent:"center" }}>
          {unread}
        </span>
      )}
    </button>
  );
}

const PASS_CONDITIONS = [
  { value:"rows = 0",    label:"rows = 0  — no bad records returned" },
  { value:"rows > 0",    label:"rows > 0  — data must be present" },
  { value:"rows > 1",    label:"rows > 1  — more than one row" },
  { value:"rows > 10",   label:"rows > 10 — at least 10 rows" },
  { value:"rows > 100",  label:"rows > 100 — at least 100 rows" },
  { value:"value = 0",   label:"value = 0  — first cell equals zero" },
  { value:"value > 0",   label:"value > 0  — first cell greater than zero" },
  { value:"value > 1",   label:"value > 1  — first cell greater than one" },
  { value:"value >= 95", label:"value ≥ 95 — percentage / score threshold" },
  { value:"custom",      label:"✏ Custom expression…" },
];

// Helper: render a smart pass-condition picker (dropdown + optional freetext)
function PassConditionPicker({ value, onChange, style }) {
  const T = useT();
  // Detect if current value matches a preset
  const isPreset = PASS_CONDITIONS.some(p => p.value !== "custom" && p.value === value);
  const isCustom = !isPreset;
  const [mode, setMode] = React.useState(isCustom ? "custom" : "preset");
  const [customVal, setCustomVal] = React.useState(isCustom ? value : "");

  const inp = {
    padding:"6px 10px", borderRadius:6, fontSize:11,
    border:`1px solid ${T.border}`, background:T.surface, color:T.text,
    fontFamily:"inherit", outline:"none", boxSizing:"border-box",
    width:"100%", ...style,
  };

  const handlePresetChange = (v) => {
    if (v === "custom") { setMode("custom"); }
    else { setMode("preset"); onChange(v); }
  };
  const handleCustomChange = (v) => {
    setCustomVal(v);
    onChange(v);
  };

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
      <select
        value={mode === "custom" ? "custom" : value}
        onChange={e => handlePresetChange(e.target.value)}
        style={inp}
      >
        {PASS_CONDITIONS.map(o => (
          <option key={o.value} value={o.value}>{o.label}</option>
        ))}
      </select>
      {mode === "custom" && (
        <div>
          <input
            value={customVal}
            onChange={e => handleCustomChange(e.target.value)}
            placeholder='e.g. rows > 50  or  value >= 0.95  or  rows = 0'
            style={{ ...inp, fontFamily:"monospace", fontSize:11 }}
            onFocus={e => e.target.style.borderColor = T.accent}
            onBlur={e => e.target.style.borderColor = T.border}
          />
          <div style={{ fontSize:9, color:T.muted, marginTop:3 }}>
            Format: <code style={{fontFamily:"monospace"}}>rows OP N</code> or <code style={{fontFamily:"monospace"}}>value OP N</code> — e.g. <code style={{fontFamily:"monospace"}}>rows &gt; 50</code>, <code style={{fontFamily:"monospace"}}>value &gt;= 0.9</code>
          </div>
        </div>
      )}
    </div>
  );
}

const SEV_COLOR = { critical:"#ef4444", high:"#f97316", medium:"#eab308", low:"#06b6d4", info:"#6366f1" };
const SEV_BG    = { critical:"#fef2f2", high:"#fff7ed", medium:"#fefce8", low:"#ecfeff", info:"#eef2ff" };

// ── RootCauseChainBanner — AI causal chain for correlated failures ────────────
function RootCauseChainBanner({ cluster, names, minsAgo, T }) {
  const [expanded,  setExpanded]  = React.useState(false);
  const [chain,     setChain]     = React.useState(null);  // [{node, type, desc}]
  const [loading,   setLoading]   = React.useState(false);
  const [dismissed, setDismissed] = React.useState(false);

  if (dismissed) return null;

  const buildChain = async () => {
    if (chain || loading) { setExpanded(true); return; }
    setLoading(true); setExpanded(true);
    try {
      // Build context from cluster run data
      const details = cluster.slice(0,6).map(r => {
        const failed = (r.check_results||[]).filter(c=>!c.passed).map(c=>c.name).join(", ") || "unknown check";
        return `${r.workflow_name||"Workflow"}: failed checks [${failed}] at ${r.started_at?.slice(11,16)||"?"}`;
      }).join("\n");

      const res = await fetch(`${API}/api/ai/chat`, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({
          system: `You are a data pipeline root cause analyst. Given correlated workflow failures, produce a causal chain as JSON array. Each item: {"node":"short label","type":"trigger|propagation|symptom","desc":"one sentence explanation"}. Max 5 nodes. Return ONLY the JSON array, no markdown.`,
          messages: [{ role:"user", content: `${cluster.length} workflows failed within 15 minutes:\n${details}\n\nBuild a root cause chain.` }],
          max_tokens: 300
        })
      });
      const d = await res.json();
      const raw = d?.content?.[0]?.text?.trim() || "[]";
      const clean = raw.replace(/```json|```/gi,"").trim();
      const arr = JSON.parse(clean.slice(clean.indexOf("["), clean.lastIndexOf("]")+1));
      setChain(Array.isArray(arr) ? arr : []);
    } catch(e) {
      setChain([{ node:"Analysis failed", type:"symptom", desc:"Could not connect to AI — check API key." }]);
    }
    setLoading(false);
  };

  const typeColor = { trigger:"#EF4444", propagation:"#F59E0B", symptom:"#6366F1" };
  const typeLabel = { trigger:"Root Cause", propagation:"Propagation", symptom:"Symptom" };

  return (
    <div style={{ marginBottom:16, borderRadius:10, overflow:"hidden",
      border:"1px solid #FED7AA", background:"#FFF7ED" }}>
      {/* Header row */}
      <div style={{ padding:"10px 14px", display:"flex", gap:10, alignItems:"flex-start" }}>
        <span style={{fontSize:16, flexShrink:0}}>🔗</span>
        <div style={{flex:1}}>
          <div style={{fontSize:12, fontWeight:700, color:"#C2410C", marginBottom:2}}>
            {cluster.length} workflows failed within 15 minutes — possible shared root cause
          </div>
          <div style={{fontSize:11, color:"#9A3412"}}>
            {names.slice(0,4).join(", ")}{names.length>4?` +${names.length-4} more`:""} · {minsAgo < 60 ? `${minsAgo}m ago` : `${Math.round(minsAgo/60)}h ago`}
          </div>
        </div>
        <div style={{display:"flex", gap:6, flexShrink:0}}>
          <button onClick={buildChain}
            style={{fontSize:10, padding:"3px 10px", borderRadius:6, cursor:"pointer",
              background: expanded ? "#FED7AA" : "#C2410C",
              border: expanded ? "1px solid #FDBA74" : "none",
              color: expanded ? "#92400E" : "white",
              fontFamily:"inherit", fontWeight:600}}>
            {loading ? "Analysing…" : expanded ? (chain ? "▲ Hide chain" : "▲ Hide") : "🔍 Root cause chain"}
          </button>
          <button onClick={()=>{
              sessionStorage.setItem("wz_agent_nudge", `Why did ${names.slice(0,3).join(", ")} all fail around the same time?`);
              window.dispatchEvent(new CustomEvent("wz_open_agent"));
            }}
            style={{fontSize:10, padding:"3px 10px", borderRadius:6, cursor:"pointer",
              background:"#FED7AA", border:"1px solid #FDBA74",
              color:"#92400E", fontFamily:"inherit", fontWeight:600}}>
            Investigate →
          </button>
          <button onClick={()=>setDismissed(true)}
            style={{background:"none", border:"none", cursor:"pointer",
              color:"#C2410C", fontSize:14, lineHeight:1}}>×</button>
        </div>
      </div>

      {/* Chain visualization */}
      {expanded && (
        <div style={{ borderTop:"1px solid #FED7AA", padding:"12px 14px",
          background:"#FFFBF7" }}>
          {loading && (
            <div style={{display:"flex", alignItems:"center", gap:8, fontSize:11, color:"#9A3412"}}>
              <Spinner size={12} color="#C2410C"/> Building causal chain…
            </div>
          )}
          {chain && chain.length > 0 && (
            <div style={{display:"flex", flexDirection:"column", gap:0}}>
              {chain.map((node, i) => (
                <div key={i} style={{display:"flex", gap:0}}>
                  {/* Connector column */}
                  <div style={{display:"flex", flexDirection:"column", alignItems:"center", width:28, flexShrink:0}}>
                    <div style={{width:12, height:12, borderRadius:"50%", flexShrink:0, marginTop:2,
                      background:typeColor[node.type]||"#6B7280",
                      boxShadow:`0 0 0 3px ${(typeColor[node.type]||"#6B7280")}25`}}/>
                    {i < chain.length-1 && (
                      <div style={{width:2, flex:1, minHeight:16,
                        background:`linear-gradient(${typeColor[node.type]||"#6B7280"},${typeColor[chain[i+1]?.type]||"#6B7280"})`,
                        opacity:0.35, margin:"3px 0"}}/>
                    )}
                  </div>
                  {/* Content */}
                  <div style={{flex:1, paddingBottom: i < chain.length-1 ? 10 : 0, paddingLeft:6}}>
                    <div style={{display:"flex", alignItems:"center", gap:6, marginBottom:2}}>
                      <span style={{fontSize:11, fontWeight:700, color:"#1C1917"}}>{node.node}</span>
                      <span style={{fontSize:9, padding:"1px 6px", borderRadius:99, fontWeight:700,
                        background:`${typeColor[node.type]||"#6B7280"}15`,
                        color:typeColor[node.type]||"#6B7280"}}>
                        {typeLabel[node.type]||node.type}
                      </span>
                    </div>
                    <div style={{fontSize:11, color:"#78716C", lineHeight:1.45}}>{node.desc}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

